import com.github.javaparser.ast.body.FieldDeclaration;
import com.github.javaparser.ast.body.VariableDeclarator;
import com.github.javaparser.ast.expr.LongLiteralExpr;
import com.github.javaparser.ast.type.ClassOrInterfaceType;
import com.github.javaparser.ast.type.Type;
import com.github.javaparser.ast.type.WildcardType;

import java.io.IOException;
import java.nio.file.Files;
import java.nio.file.Path;
import java.nio.file.Paths;
import java.util.List;
import java.util.Optional;
import java.util.stream.Collectors;

public class Main {
    public static void main(String[] args) throws IOException {
        if (args.length < 1) {
            System.err.println("Usage: java Main <source-directory>");
            System.exit(1);
        }

        Path sourceDir = Paths.get(args[0]);

        ParserConfiguration config = new ParserConfiguration()
                .setLanguageLevel(ParserConfiguration.LanguageLevel.JAVA_11);

        JavaParser parser = new JavaParser(config);

        List<Path> javaFiles = Files.walk(sourceDir)
                .filter(p -> p.toString().endsWith(".java"))
                .collect(Collectors.toList());

        for (Path file : javaFiles) {
            try {
                ParseResult<CompilationUnit> result = parser.parse(file);
                result.getResult().ifPresent(cu -> {
                    boolean modified = false;

                    modified = addSerialVersionUID(cu) || modified;
                    modified = fixRawTypes(cu) || modified;

                    if (modified) {
                        try {
                            Files.writeString(file, cu.toString());
                            System.out.println("Fixed: " + file);
                        } catch (IOException e) {
                            System.err.println("Error writing " + file + ": " + e.getMessage());
                        }
                    }
                });
            } catch (Exception e) {
                System.err.println("Error processing " + file + ": " + e.getMessage());
            }
        }

        System.out.println("Transformation complete.");
    }

    private static boolean addSerialVersionUID(CompilationUnit cu) {
        boolean modified = false;

        List<ClassOrInterfaceDeclaration> classes = cu.findAll(ClassOrInterfaceDeclaration.class);

        for (ClassOrInterfaceDeclaration clazz : classes) {
            if (clazz.isInterface()) {
                continue;
            }

            boolean implementsSerializable = false;
            for (ClassOrInterfaceType implementedType : clazz.getImplementedTypes()) {
                if ("Serializable".equals(implementedType.getNameAsString()) ||
                    "java.io.Serializable".equals(implementedType.getNameWithScope())) {
                    implementsSerializable = true;
                    break;
                }
            }

            if (!implementsSerializable) {
                Optional<ClassOrInterfaceType> extendedType = clazz.getExtendedTypes().stream().findFirst();
                if (extendedType.isPresent()) {
                    String extendedName = extendedType.get().getNameAsString();
                    if ("Exception".equals(extendedName) || "RuntimeException".equals(extendedName) ||
                        "java.lang.Exception".equals(extendedType.get().getNameWithScope()) ||
                        "java.lang.RuntimeException".equals(extendedType.get().getNameWithScope())) {
                        implementsSerializable = true;
                    }
                }
            }

            if (implementsSerializable) {
                boolean hasSerialVersionUID = clazz.getFields().stream()
                        .anyMatch(field -> field.getVariables().stream()
                                .anyMatch(v -> "serialVersionUID".equals(v.getNameAsString())));

                if (!hasSerialVersionUID) {
                    com.github.javaparser.ast.type.PrimitiveType longType = 
                        new com.github.javaparser.ast.type.PrimitiveType(com.github.javaparser.ast.type.PrimitiveType.Primitive.LONG);

                    VariableDeclarator declarator = new VariableDeclarator(longType, "serialVersionUID", new LongLiteralExpr("1L"));

                    NodeList<VariableDeclarator> vars = new NodeList<>();
                    vars.add(declarator);

                    NodeList<Modifier> modifiers = new NodeList<>();
                    modifiers.add(new Modifier(Modifier.Keyword.PRIVATE));
                    modifiers.add(new Modifier(Modifier.Keyword.STATIC));
                    modifiers.add(new Modifier(Modifier.Keyword.FINAL));

                    FieldDeclaration field = new FieldDeclaration(modifiers, vars);

                    clazz.getMembers().add(0, field);
                    modified = true;
                    System.out.println("  Added serialVersionUID to: " + clazz.getNameAsString());
                }
            }
        }

        return modified;
    }

    private static boolean fixRawTypes(CompilationUnit cu) {
        boolean modified = false;

        List<ClassOrInterfaceType> types = cu.findAll(ClassOrInterfaceType.class);

        for (ClassOrInterfaceType type : types) {
            if (!type.getTypeArguments().isPresent() && type.getTypeArguments().isEmpty()) {
                String typeName = type.getNameAsString();

                if ("Class".equals(typeName) || "java.lang.Class".equals(type.getNameWithScope())) {
                    NodeList<Type> typeArgs = new NodeList<>();
                    WildcardType wildcard = new WildcardType();
                    typeArgs.add(wildcard);
                    type.setTypeArguments(typeArgs);
                    modified = true;
                } else if ("Constructor".equals(typeName) || "java.lang.reflect.Constructor".equals(type.getNameWithScope())) {
                    NodeList<Type> typeArgs = new NodeList<>();
                    WildcardType wildcard = new WildcardType();
                    typeArgs.add(wildcard);
                    type.setTypeArguments(typeArgs);
                    modified = true;
                } else if ("AbstractProject".equals(typeName) || type.getNameWithScope().contains("AbstractProject")) {
                    NodeList<Type> typeArgs = new NodeList<>();
                    WildcardType wildcard1 = new WildcardType();
                    WildcardType wildcard2 = new WildcardType();
                    typeArgs.add(wildcard1);
                    typeArgs.add(wildcard2);
                    type.setTypeArguments(typeArgs);
                    modified = true;
                }
            }
        }

        if (modified) {
            System.out.println("  Fixed raw types in: " + cu.getPrimaryTypeName().orElse("unknown"));
        }

        return modified;
    }
}

